CREATE TABLE IF NOT EXISTS "User" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"name" VARCHAR(255) NOT NULL UNIQUE,
	"email" VARCHAR(255) NOT NULL UNIQUE,
	"password" VARCHAR(255) NOT NULL,
	"role" VARCHAR(255) NOT NULL,
	"create_at" DATE NOT NULL,
	PRIMARY KEY("id")
);

CREATE TABLE IF NOT EXISTS "Project" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"titre" VARCHAR(255) NOT NULL,
	"description" TEXT NOT NULL,
	"image" VARCHAR(255) NOT NULL,
	"technology_id" VARCHAR(255) NOT NULL,
	"demo_url" TEXT NOT NULL UNIQUE,
	"create_at" DATE NOT NULL,
	"update_at" DATE NOT NULL,
	PRIMARY KEY("id")
	FOREIGN KEY ("user_id") REFERENCES "User"("id")
) 

CREATE TABLE IF NOT EXISTS "Technology" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"name" VARCHAR(255) NOT NULL UNIQUE,
	"icon" VARCHAR(255) NOT NULL,
	"create_at" DATE NOT NULL,
	PRIMARY KEY("id")
);

CREATE TABLE IF NOT EXISTS "ProjectTechnology" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"project_id" VARCHAR(255),
	"technology_id" VARCHAR(255),
	PRIMARY KEY("project_id") REFERENCES "Project"("id"),
	PRIMARY KEY("technology_id") REFERENCES "Technology"("id")
);



ALTER TABLE "Project"
ADD FOREIGN KEY("id") REFERENCES "User"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "ProjectTechnology"
ADD FOREIGN KEY("id") REFERENCES "Project"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "Technology"
ADD FOREIGN KEY("id") REFERENCES "ProjectTechnology"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;